const { execSync, spawn } = require\('child_process'\);
const http = require\('http'\);
const fs = require\('fs'\);

// Launch Chrome with remote debugging
const chrome = spawn\('google-chrome', [
  '--remote-debugging-port=9222',
  '--no-sandbox',
  '--disable-gpu', 
  '--headless=new',
  '--window-size=390,844',
  'about:blank'
], { stdio: 'ignore' }\);

const wait = ms => new Promise\(r => setTimeout\(r, ms\)\);

function cdpFetch\(path, method, body\) {
  return new Promise\(\(resolve, reject\) => {
    const data = body ? JSON.stringify\(body\) : '';
    const opts = {
      hostname: 'localhost', port: 9222,
      path, method: method || 'GET',
      headers: data ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength\(data\) } : {}
    };
    const req = http.request\(opts, res => {
      let d = '';
      res.on\('data', c => d += c\);
      res.on\('end', \(\) => resolve\(d ? JSON.parse\(d\) : {}\)\);
    }\);
    req.on\('error', reject\);
    if \(data\) req.write\(data\);
    req.end\(\);
  }\);
}

function sendCmd\(ws, id, method, params\) {
  return new Promise\(\(resolve, reject\) => {
    const msg = JSON.stringify\({ id, method, params: params || {} }\);
    ws.send\(msg\);
    const handler = \(data\) => {
      const d = JSON.parse\(data\);
      if \(d.id === id\) { ws.off\('message', handler\); resolve\(d.result\); }
    };
    ws.on\('message', handler\);
    setTimeout\(\(\) => reject\(new Error\('timeout'\)\), 10000\);
  }\);
}

async function main\(\) {
  await wait\(2000\);
  const tabs = await cdpFetch\('/json'\);
  const wsUrl = tabs[0].webSocketDebuggerUrl;

  const { WebSocket } = await import\('ws'\).catch\(\(\) => \({ WebSocket: null }\)\);
  if \(!WebSocket\) { console.log\('no ws'\); chrome.kill\(\); return; }

  const ws = new WebSocket\(wsUrl\);
  await new Promise\(r => ws.on\('open', r\)\);

  let cmdId = 1;
  await sendCmd\(ws, cmdId++, 'Page.enable'\);
  await sendCmd\(ws, cmdId++, 'Page.navigate', { url: 'http://localhost:5173/' }\);
  await wait\(4000\);

  const shot = await sendCmd\(ws, cmdId++, 'Page.captureScreenshot', { format: 'png', clip: { x:0, y:0, width:390, height:844, scale:2 } }\);
  fs.writeFileSync\('/tmp/screenshot-home.png', Buffer.from\(shot.data, 'base64'\)\);
  console.log\('done'\);
  ws.close\(\);
  chrome.kill\(\);
}
main\(\).catch\(e => { console.error\(e.message\); chrome.kill\(\); }\);
EOF
node /tmp/ss.js)
